     1→<!DOCTYPE html>
     2→<html lang="en">
     3→<head>
     4→  <meta charset="UTF-8" />
     5→  <meta name="viewport" content="width=device-width, initial-scale=1.0" />
     6→  <title>Monta EV Charging Dashboard</title>
     7→  <script src="https://cdnjs.cloudflare.com/ajax/libs/Chart.js/4.4.1/chart.umd.min.js"></script>
     8→  <style>
     9→    * { box-sizing: border-box; margin: 0; padding: 0; }
    10→    :root {
    11→      --green: #00C48C;
    12→      --green-dark: #00a377;
    13→      --green-light: #e6faf4;
    14→      --bg: #f4f6f9;
    15→      --card: #ffffff;
    16→      --text: #1a2235;
    17→      --text-muted: #6b7280;
    18→      --border: #e5e7eb;
    19→      --shadow: 0 1px 4px rgba(0,0,0,0.08), 0 4px 16px rgba(0,0,0,0.04);
    20→      --red: #ef4444;
    21→      --amber: #f59e0b;
    22→      --blue: #3b82f6;
    23→    }
    24→    body {
    25→      font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif;
    26→      background: var(--bg);
    27→      color: var(--text);
    28→      min-height: 100vh;
    29→    }
    30→
    31→    /* ── NAV ── */
    32→    nav {
    33→      background: var(--card);
    34→      border-bottom: 1px solid var(--border);
    35→      padding: 0 28px;
    36→      display: flex;
    37→      align-items: center;
    38→      justify-content: space-between;
    39→      height: 60px;
    40→      position: sticky;
    41→      top: 0;
    42→      z-index: 100;
    43→    }
    44→    .nav-logo {
    45→      display: flex;
    46→      align-items: center;
    47→      gap: 10px;
    48→      font-weight: 700;
    49→      font-size: 18px;
    50→      color: var(--text);
    51→    }
    52→    .nav-logo svg { width: 32px; height: 32px; }
    53→    .nav-right { display: flex; align-items: center; gap: 14px; }
    54→    #status-badge {
    55→      font-size: 12px;
    56→      font-weight: 600;
    57→      padding: 4px 12px;
    58→      border-radius: 20px;
    59→      background: #fef3c7;
    60→      color: #92400e;
    61→    }
    62→    #status-badge.connected { background: var(--green-light); color: #065f46; }
    63→    #status-badge.error { background: #fee2e2; color: #991b1b; }
    64→    #refresh-btn {
    65→      background: var(--green);
    66→      color: white;
    67→      border: none;
    68→      padding: 7px 16px;
    69→      border-radius: 8px;
    70→      font-size: 13px;
    71→      font-weight: 600;
    72→      cursor: pointer;
    73→      transition: background 0.2s;
    74→    }
    75→    #refresh-btn:hover { background: var(--green-dark); }
    76→    #refresh-btn:disabled { opacity: 0.5; cursor: not-allowed; }
    77→
    78→    /* ── MAIN ── */
    79→    main { max-width: 1280px; margin: 0 auto; padding: 28px 24px; }
    80→
    81→    /* ── FILTER BAR ── */
    82→    .filter-bar {
    83→      background: var(--card);
    84→      border: 1px solid var(--border);
    85→      border-radius: 12px;
    86→      padding: 14px 20px;
    87→      display: flex;
    88→      align-items: center;
    89→      gap: 16px;
    90→      margin-bottom: 24px;
    91→      flex-wrap: wrap;
    92→    }
    93→    .filter-bar label { font-size: 13px; color: var(--text-muted); font-weight: 500; }
    94→    .filter-bar select, .filter-bar input {
    95→      border: 1px solid var(--border);
    96→      border-radius: 8px;
    97→      padding: 6px 12px;
    98→      font-size: 13px;
    99→      color: var(--text);
   100→      background: white;
   101→      cursor: pointer;
   102→    }
   103→    .filter-bar select:focus, .filter-bar input:focus { outline: 2px solid var(--green); }
   104→
   105→    /* ── KPI CARDS ── */
   106→    .kpi-grid {
   107→      display: grid;
   108→      grid-template-columns: repeat(4, 1fr);
   109→      gap: 16px;
   110→      margin-bottom: 24px;
   111→    }
   112→    .kpi-card {
   113→      background: var(--card);
   114→      border: 1px solid var(--border);
   115→      border-radius: 14px;
   116→      padding: 20px 22px;
   117→      box-shadow: var(--shadow);
   118→    }
   119→    .kpi-label { font-size: 12px; font-weight: 600; color: var(--text-muted); text-transform: uppercase; letter-spacing: 0.5px; margin-bottom: 8px; }
   120→    .kpi-value { font-size: 28px; font-weight: 700; color: var(--text); line-height: 1; margin-bottom: 6px; }
   121→    .kpi-sub { font-size: 12px; color: var(--text-muted); }
   122→    .kpi-icon { width: 40px; height: 40px; border-radius: 10px; display: flex; align-items: center; justify-content: center; margin-bottom: 12px; font-size: 18px; }
   123→    .icon-green { background: var(--green-light); }
   124→    .icon-blue { background: #eff6ff; }
   125→    .icon-amber { background: #fffbeb; }
   126→    .icon-purple { background: #f5f3ff; }
   127→
   128→    /* ── CHART GRID ── */
   129→    .chart-grid {
   130→      display: grid;
   131→      grid-template-columns: 2fr 1fr;
   132→      gap: 16px;
   133→      margin-bottom: 16px;
   134→    }
   135→    .chart-grid-bottom {
   136→      display: grid;
   137→      grid-template-columns: 1fr 1fr;
   138→      gap: 16px;
   139→      margin-bottom: 24px;
   140→    }
   141→    .chart-card {
   142→      background: var(--card);
   143→      border: 1px solid var(--border);
   144→      border-radius: 14px;
   145→      padding: 22px;
   146→      box-shadow: var(--shadow);
   147→    }
   148→    .chart-title {
   149→      font-size: 14px;
   150→      font-weight: 600;
   151→      color: var(--text);
   152→      margin-bottom: 4px;
   153→    }
   154→    .chart-subtitle { font-size: 12px; color: var(--text-muted); margin-bottom: 16px; }
   155→    .chart-wrap { position: relative; height: 240px; }
   156→    .chart-wrap-sm { position: relative; height: 200px; }
   157→
   158→    /* ── TABLE ── */
   159→    .table-card {
   160→      background: var(--card);
   161→      border: 1px solid var(--border);
   162→      border-radius: 14px;
   163→      box-shadow: var(--shadow);
   164→      overflow: hidden;
   165→      margin-bottom: 24px;
   166→    }
   167→    .table-header {
   168→      padding: 18px 22px 14px;
   169→      border-bottom: 1px solid var(--border);
   170→      display: flex;
   171→      align-items: center;
   172→      justify-content: space-between;
   173→    }
   174→    .table-title { font-size: 14px; font-weight: 600; }
   175→    .table-count { font-size: 12px; color: var(--text-muted); }
   176→    table { width: 100%; border-collapse: collapse; }
   177→    th {
   178→      text-align: left;
   179→      font-size: 11px;
   180→      font-weight: 600;
   181→      text-transform: uppercase;
   182→      letter-spacing: 0.5px;
   183→      color: var(--text-muted);
   184→      padding: 10px 16px;
   185→      background: #f9fafb;
   186→      border-bottom: 1px solid var(--border);
   187→    }
   188→    td { padding: 11px 16px; font-size: 13px; border-bottom: 1px solid var(--border); }
   189→    tr:last-child td { border-bottom: none; }
   190→    tr:hover td { background: #f9fafb; }
   191→    .badge {
   192→      display: inline-block;
   193→      padding: 2px 9px;
   194→      border-radius: 12px;
   195→      font-size: 11px;
   196→      font-weight: 600;
   197→    }
   198→    .badge-green { background: var(--green-light); color: #065f46; }
   199→    .badge-blue { background: #dbeafe; color: #1e40af; }
   200→    .badge-amber { background: #fef3c7; color: #92400e; }
   201→    .badge-red { background: #fee2e2; color: #991b1b; }
   202→    .badge-gray { background: #f3f4f6; color: #374151; }
   203→
   204→    /* ── CHARGE POINT STATUS GRID ── */
   205→    .cp-grid {
   206→      display: grid;
   207→      grid-template-columns: repeat(auto-fill, minmax(200px, 1fr));
   208→      gap: 10px;
   209→      max-height: 280px;
   210→      overflow-y: auto;
   211→      padding-right: 4px;
   212→    }
   213→    .cp-item {
   214→      border: 1px solid var(--border);
   215→      border-radius: 10px;
   216→      padding: 12px 14px;
   217→      background: #fafafa;
   218→    }
   219→    .cp-name { font-size: 12px; font-weight: 600; color: var(--text); margin-bottom: 4px; white-space: nowrap; overflow: hidden; text-overflow: ellipsis; }
   220→    .cp-meta { font-size: 11px; color: var(--text-muted); }
   221→
   222→    /* ── LOADING OVERLAY ── */
   223→    #loading-overlay {
   224→      position: fixed;
   225→      inset: 0;
   226→      background: rgba(255,255,255,0.85);
   227→      display: flex;
   228→      flex-direction: column;
   229→      align-items: center;
   230→      justify-content: center;
   231→      z-index: 1000;
   232→    }
   233→    #loading-overlay.hidden { display: none; }
   234→    .spinner {
   235→      width: 44px;
   236→      height: 44px;
   237→      border: 3px solid var(--border);
   238→      border-top-color: var(--green);
   239→      border-radius: 50%;
   240→      animation: spin 0.8s linear infinite;
   241→      margin-bottom: 14px;
   242→    }
   243→    @keyframes spin { to { transform: rotate(360deg); } }
   244→    #loading-msg { font-size: 14px; color: var(--text-muted); }
   245→
   246→    /* ── ERROR CARD ── */
   247→    #error-card {
   248→      background: #fff5f5;
   249→      border: 1px solid #fca5a5;
   250→      border-radius: 12px;
   251→      padding: 20px 24px;
   252→      margin-bottom: 24px;
   253→      display: none;
   254→    }
   255→    #error-card.show { display: block; }
   256→    #error-text { font-size: 13px; color: #991b1b; }
   257→
   258→    /* ── RESPONSIVE ── */
   259→    @media (max-width: 900px) {
   260→      .kpi-grid { grid-template-columns: repeat(2, 1fr); }
   261→      .chart-grid, .chart-grid-bottom { grid-template-columns: 1fr; }
   262→    }
   263→    @media (max-width: 500px) {
   264→      .kpi-grid { grid-template-columns: 1fr; }
   265→    }
   266→
   267→    /* ── SCROLLBAR ── */
   268→    ::-webkit-scrollbar { width: 6px; height: 6px; }
   269→    ::-webkit-scrollbar-track { background: transparent; }
   270→    ::-webkit-scrollbar-thumb { background: #d1d5db; border-radius: 3px; }
   271→
   272→    .no-data { text-align: center; padding: 40px; color: var(--text-muted); font-size: 14px; }
   273→  </style>
   274→</head>
   275→<body>
   276→
   277→<!-- LOADING OVERLAY -->
   278→<div id="loading-overlay">
   279→  <div class="spinner"></div>
   280→  <div id="loading-msg">Connecting to Monta API…</div>
   281→</div>
   282→
   283→<!-- NAV -->
   284→<nav>
   285→  <div class="nav-logo">
   286→    <svg viewBox="0 0 32 32" fill="none" xmlns="http://www.w3.org/2000/svg">
   287→      <rect width="32" height="32" rx="8" fill="#00C48C"/>
   288→      <path d="M10 22L16 8L22 22" stroke="white" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round"/>
   289→      <path d="M12.5 17.5H19.5" stroke="white" stroke-width="2.5" stroke-linecap="round"/>
   290→    </svg>
   291→    Monta Dashboard
   292→  </div>
   293→  <div class="nav-right">
   294→    <span id="status-badge">Connecting…</span>
   295→    <button id="refresh-btn" onclick="loadAll()">↻ Refresh</button>
   296→  </div>
   297→</nav>
   298→
   299→<!-- MAIN -->
   300→<main>
   301→  <!-- ERROR -->
   302→  <div id="error-card"><strong>API Error:</strong> <span id="error-text"></span></div>
   303→
   304→  <!-- FILTER BAR -->
   305→  <div class="filter-bar">
   306→    <label>Period:</label>
   307→    <select id="period-select" onchange="loadAll()">
   308→      <option value="7">Last 7 days</option>
   309→      <option value="30" selected>Last 30 days</option>
   310→      <option value="90">Last 90 days</option>
   311→      <option value="180">Last 6 months</option>
   312→    </select>
   313→    <label style="margin-left:8px;">Group by:</label>
   314→    <select id="group-select" onchange="redrawCharts()">
   315→      <option value="day">Day</option>
   316→      <option value="week">Week</option>
   317→    </select>
   318→    <span id="last-updated" style="margin-left:auto;font-size:12px;color:var(--text-muted);"></span>
   319→  </div>
   320→
   321→  <!-- KPI CARDS -->
   322→  <div class="kpi-grid">
   323→    <div class="kpi-card">
   324→      <div class="kpi-icon icon-green">⚡</div>
   325→      <div class="kpi-label">Total Energy</div>
   326→      <div class="kpi-value" id="kpi-energy">—</div>
   327→      <div class="kpi-sub" id="kpi-energy-sub">kWh delivered</div>
   328→    </div>
   329→    <div class="kpi-card">
   330→      <div class="kpi-icon icon-blue">🔌</div>
   331→      <div class="kpi-label">Total Sessions</div>
   332→      <div class="kpi-value" id="kpi-sessions">—</div>
   333→      <div class="kpi-sub" id="kpi-sessions-sub">charging sessions</div>
   334→    </div>
   335→    <div class="kpi-card">
   336→      <div class="kpi-icon icon-amber">⏱</div>
   337→      <div class="kpi-label">Avg. Session Duration</div>
   338→      <div class="kpi-value" id="kpi-duration">—</div>
   339→      <div class="kpi-sub">minutes per session</div>
   340→    </div>
   341→    <div class="kpi-card">
   342→      <div class="kpi-icon icon-purple">🏠</div>
   343→      <div class="kpi-label">Charge Points</div>
   344→      <div class="kpi-value" id="kpi-chargepoints">—</div>
   345→      <div class="kpi-sub" id="kpi-cp-sub">in network</div>
   346→    </div>
   347→  </div>
   348→
   349→  <!-- CHARTS ROW 1 -->
   350→  <div class="chart-grid">
   351→    <div class="chart-card">
   352→      <div class="chart-title">Energy Delivered Over Time</div>
   353→      <div class="chart-subtitle">kWh per period</div>
   354→      <div class="chart-wrap"><canvas id="chart-energy"></canvas></div>
   355→    </div>
   356→    <div class="chart-card">
   357→      <div class="chart-title">Charge Point Status</div>
   358→      <div class="chart-subtitle">Current snapshot</div>
   359→      <div class="chart-wrap"><canvas id="chart-status"></canvas></div>
   360→    </div>
   361→  </div>
   362→
   363→  <!-- CHARTS ROW 2 -->
   364→  <div class="chart-grid-bottom">
   365→    <div class="chart-card">
   366→      <div class="chart-title">Sessions Over Time</div>
   367→      <div class="chart-subtitle">Number of charging sessions</div>
   368→      <div class="chart-wrap-sm"><canvas id="chart-sessions"></canvas></div>
   369→    </div>
   370→    <div class="chart-card">
   371→      <div class="chart-title">Avg. kWh per Session</div>
   372→      <div class="chart-subtitle">Energy efficiency trend</div>
   373→      <div class="chart-wrap-sm"><canvas id="chart-avg-kwh"></canvas></div>
   374→    </div>
   375→  </div>
   376→
   377→  <!-- CHARGE POINTS TABLE -->
   378→  <div class="table-card">
   379→    <div class="table-header">
   380→      <div>
   381→        <div class="table-title">Charge Points</div>
   382→        <div class="table-count" id="cp-count"></div>
   383→      </div>
   384→    </div>
   385→    <div style="padding:16px;" id="cp-container">
   386→      <div class="no-data">Loading charge points…</div>
   387→    </div>
   388→  </div>
   389→
   390→  <!-- RECENT CHARGES TABLE -->
   391→  <div class="table-card">
   392→    <div class="table-header">
   393→      <div>
   394→        <div class="table-title">Recent Charges</div>
   395→        <div class="table-count" id="charges-count"></div>
   396→      </div>
   397→    </div>
   398→    <div id="charges-table-wrap">
   399→      <div class="no-data">Loading charges…</div>
   400→    </div>
   401→  </div>
   402→</main>
   403→
   404→<script>
   405→// ─── CONFIG ──────────────────────────────────────────────────────────────────
   406→const CLIENT_ID     = '47095201-e97d-4697-ae5a-d7914655f6cf';
   407→const CLIENT_SECRET = '184d8bdb-7820-4d1e-b364-fb61ee3e068b';
   408→const BASE_URL      = 'https://partner-api.monta.com/api/v1';
   409→
   410→// ─── STATE ───────────────────────────────────────────────────────────────────
   411→let accessToken   = null;
   412→let allCharges    = [];
   413→let allCPs        = [];
   414→let chartEnergy   = null;
   415→let chartSessions = null;
   416→let chartStatus   = null;
   417→let chartAvgKwh   = null;
   418→
   419→// ─── UTILS ───────────────────────────────────────────────────────────────────
   420→const $  = id => document.getElementById(id);
   421→const fmt = n => n == null ? '—' : new Intl.NumberFormat('en-US', {maximumFractionDigits: 1}).format(n);
   422→const fmtDate = iso => {
   423→  if (!iso) return '—';
   424→  const d = new Date(iso);
   425→  return d.toLocaleDateString('en-GB', {day:'2-digit', month:'short', year:'2-digit'}) + ' ' +
   426→         d.toLocaleTimeString('en-GB', {hour:'2-digit', minute:'2-digit'});
   427→};
   428→const fmtDuration = mins => {
   429→  if (mins == null) return '—';
   430→  if (mins < 60) return `${Math.round(mins)}m`;
   431→  return `${Math.floor(mins/60)}h ${Math.round(mins%60)}m`;
   432→};
   433→
   434→function setLoading(msg) {
   435→  $('loading-overlay').classList.remove('hidden');
   436→  $('loading-msg').textContent = msg;
   437→}
   438→function hideLoading() {
   439→  $('loading-overlay').classList.add('hidden');
   440→}
   441→function showError(msg) {
   442→  $('error-card').classList.add('show');
   443→  $('error-text').textContent = msg;
   444→}
   445→function clearError() {
   446→  $('error-card').classList.remove('show');
   447→}
   448→
   449→// ─── AUTH ────────────────────────────────────────────────────────────────────
   450→async function authenticate() {
   451→  setLoading('Authenticating with Monta API…');
   452→  const res = await fetch(`${BASE_URL}/auth/token`, {
   453→    method: 'POST',
   454→    headers: {'Content-Type': 'application/json'},
   455→    body: JSON.stringify({clientId: CLIENT_ID, clientSecret: CLIENT_SECRET})
   456→  });
   457→  if (!res.ok) {
   458→    const err = await res.text();
   459→    throw new Error(`Auth failed (${res.status}): ${err}`);
   460→  }
   461→  const data = await res.json();
   462→  accessToken = data.accessToken || data.access_token || data.token;
   463→  if (!accessToken) throw new Error('No access token in response: ' + JSON.stringify(data));
   464→  return accessToken;
   465→}
   466→
   467→// ─── API HELPER ───────────────────────────────────────────────────────────────
   468→async function apiFetch(path, params = {}) {
   469→  const url = new URL(`${BASE_URL}${path}`);
   470→  Object.entries(params).forEach(([k,v]) => v != null && url.searchParams.set(k, v));
   471→  const res = await fetch(url.toString(), {
   472→    headers: {
   473→      'Authorization': `Bearer ${accessToken}`,
   474→      'Content-Type': 'application/json'
   475→    }
   476→  });
   477→  if (res.status === 401) {
   478→    // Re-auth and retry
   479→    await authenticate();
   480→    return apiFetch(path, params);
   481→  }
   482→  if (!res.ok) {
   483→    const err = await res.text();
   484→    throw new Error(`API error ${res.status} on ${path}: ${err}`);
   485→  }
   486→  return res.json();
   487→}
   488→
   489→// ─── PAGINATED FETCH ─────────────────────────────────────────────────────────
   490→async function fetchAll(path, params = {}, pageKey = 'page', pageSize = 100) {
   491→  let results = [];
   492→  let page = 0;
   493→  while (true) {
   494→    const data = await apiFetch(path, {...params, [pageKey]: page, pageSize});
   495→    const items = data.data || data.items || data.charges || data.chargePoints || data.sites || [];
   496→    results = results.concat(items);
   497→    const total = data.total || data.totalCount || data.count;
   498→    if (!items.length || (total && results.length >= total) || items.length < pageSize) break;
   499→    page++;
   500→  }
   501→  return results;
   502→}
   503→
   504→// ─── DATE HELPERS ─────────────────────────────────────────────────────────────
   505→function getDateRange() {
   506→  const days = parseInt($('period-select').value) || 30;
   507→  const end = new Date();
   508→  const start = new Date();
   509→  start.setDate(start.getDate() - days);
   510→  return {
   511→    startDate: start.toISOString().split('T')[0],
   512→    endDate:   end.toISOString().split('T')[0],
   513→    days
   514→  };
   515→}
   516→
   517→// ─── GROUP BY DAY / WEEK ──────────────────────────────────────────────────────
   518→function groupChargesByPeriod(charges) {
   519→  const groupBy = $('group-select').value;
   520→  const map = {};
   521→
   522→  charges.forEach(c => {
   523→    const raw = c.createdAt || c.startedAt || c.startTime || c.created_at;
   524→    if (!raw) return;
   525→    const d = new Date(raw);
   526→    let key;
   527→    if (groupBy === 'week') {
   528→      const dow = d.getDay(); // 0=Sun
   529→      const mon = new Date(d);
   530→      mon.setDate(d.getDate() - ((dow + 6) % 7));
   531→      key = mon.toISOString().split('T')[0];
   532→    } else {
   533→      key = d.toISOString().split('T')[0];
   534→    }
   535→    if (!map[key]) map[key] = {energy: 0, sessions: 0};
   536→    const kwh = c.kwh ?? c.energyKwh ?? c.energy ?? 0;
   537→    map[key].energy   += kwh;
   538→    map[key].sessions += 1;
   539→  });
   540→
   541→  const sorted = Object.keys(map).sort();
   542→  const labels = sorted.map(k => {
   543→    const d = new Date(k + 'T12:00:00');
   544→    return groupBy === 'week'
   545→      ? 'W/c ' + d.toLocaleDateString('en-GB', {day:'2-digit', month:'short'})
   546→      : d.toLocaleDateString('en-GB', {day:'2-digit', month:'short'});
   547→  });
   548→  return {
   549→    labels,
   550→    energy:   sorted.map(k => map[k].energy),
   551→    sessions: sorted.map(k => map[k].sessions),
   552→    avgKwh:   sorted.map(k => map[k].sessions ? map[k].energy / map[k].sessions : 0)
   553→  };
   554→}
   555→
   556→// ─── CHART HELPERS ────────────────────────────────────────────────────────────
   557→const GREEN = '#00C48C';
   558→const BLUE  = '#3b82f6';
   559→const AMBER = '#f59e0b';
   560→const GRAY  = '#6b7280';
   561→
   562→function destroyChart(chartRef) {
   563→  if (chartRef) { chartRef.destroy(); }
   564→  return null;
   565→}
   566→
   567→function buildLineChart(id, labels, data, label, color) {
   568→  const ctx = $(id).getContext('2d');
   569→  return new Chart(ctx, {
   570→    type: 'bar',
   571→    data: {
   572→      labels,
   573→      datasets: [{
   574→        label,
   575→        data,
   576→        backgroundColor: color + '33',
   577→        borderColor: color,
   578→        borderWidth: 2,
   579→        borderRadius: 4,
   580→        borderSkipped: false,
   581→      }]
   582→    },
   583→    options: {
   584→      responsive: true,
   585→      maintainAspectRatio: false,
   586→      plugins: {
   587→        legend: { display: false },
   588→        tooltip: { callbacks: { label: ctx => ` ${fmt(ctx.raw)}` } }
   589→      },
   590→      scales: {
   591→        x: { grid: { display: false }, ticks: { font: { size: 11 }, maxRotation: 45 } },
   592→        y: { grid: { color: '#f0f0f0' }, ticks: { font: { size: 11 } }, beginAtZero: true }
   593→      }
   594→    }
   595→  });
   596→}
   597→
   598→function buildDonut(id, labels, data, colors) {
   599→  const ctx = $(id).getContext('2d');
   600→  return new Chart(ctx, {
   601→    type: 'doughnut',
   602→    data: {
   603→      labels,
   604→      datasets: [{ data, backgroundColor: colors, borderWidth: 2, borderColor: '#fff' }]
   605→    },
   606→    options: {
   607→      responsive: true,
   608→      maintainAspectRatio: false,
   609→      plugins: {
   610→        legend: {
   611→          position: 'bottom',
   612→          labels: { font: { size: 11 }, padding: 12 }
   613→        },
   614→        tooltip: { callbacks: { label: ctx => ` ${ctx.label}: ${ctx.raw}` } }
   615→      },
   616→      cutout: '62%'
   617→    }
   618→  });
   619→}
   620→
   621→// ─── RENDER KPIs ─────────────────────────────────────────────────────────────
   622→function renderKPIs(charges, cps) {
   623→  const totalEnergy   = charges.reduce((s, c) => s + (c.kwh ?? c.energyKwh ?? c.energy ?? 0), 0);
   624→  const totalSessions = charges.length;
   625→
   626→  // Duration in minutes
   627→  const durations = charges
   628→    .map(c => {
   629→      const start = c.startedAt || c.startTime || c.createdAt;
   630→      const end   = c.stoppedAt || c.endTime   || c.finishedAt;
   631→      if (!start || !end) return null;
   632→      return (new Date(end) - new Date(start)) / 60000;
   633→    })
   634→    .filter(d => d != null && d > 0 && d < 1440);
   635→
   636→  const avgDuration = durations.length ? durations.reduce((s,d)=>s+d,0)/durations.length : null;
   637→
   638→  $('kpi-energy').textContent    = fmt(totalEnergy) + ' kWh';
   639→  $('kpi-sessions').textContent  = fmt(totalSessions);
   640→  $('kpi-duration').textContent  = avgDuration ? fmtDuration(avgDuration) : '—';
   641→  $('kpi-chargepoints').textContent = fmt(cps.length);
   642→
   643→  const {days} = getDateRange();
   644→  $('kpi-energy-sub').textContent   = `kWh over last ${days} days`;
   645→  $('kpi-sessions-sub').textContent = `over last ${days} days`;
   646→  $('kpi-cp-sub').textContent       = `${cps.filter(cp => (cp.status||'').toLowerCase() === 'available').length} available now`;
   647→}
   648→
   649→// ─── RENDER CHARGE POINTS ─────────────────────────────────────────────────────
   650→function renderChargePoints(cps) {
   651→  $('cp-count').textContent = `${cps.length} charge points`;
   652→  if (!cps.length) {
   653→    $('cp-container').innerHTML = '<div class="no-data">No charge points found in this account.</div>';
   654→    return;
   655→  }
   656→  const statusColor = s => {
   657→    const st = (s||'').toLowerCase();
   658→    if (st === 'available') return 'badge-green';
   659→    if (st === 'charging' || st === 'busy' || st === 'occupied') return 'badge-blue';
   660→    if (st === 'offline' || st === 'unavailable' || st === 'faulted') return 'badge-red';
   661→    return 'badge-gray';
   662→  };
   663→
   664→  $('cp-container').innerHTML = `
   665→    <div class="cp-grid">
   666→      ${cps.map(cp => {
   667→        const name = cp.name || cp.id || 'Unknown';
   668→        const status = cp.status || 'Unknown';
   669→        return `
   670→          <div class="cp-item">
   671→            <div class="cp-name" title="${name}">${name}</div>
   672→            <div style="margin:4px 0;"><span class="badge ${statusColor(status)}">${status}</span></div>
   673→            <div class="cp-meta">${cp.model || cp.chargePointModel || ''} ${cp.maxPower ? '· ' + cp.maxPower + ' kW' : ''}</div>
   674→          </div>`;
   675→      }).join('')}
   676→    </div>`;
   677→}
   678→
   679→// ─── RENDER CHARGES TABLE ─────────────────────────────────────────────────────
   680→function renderChargesTable(charges) {
   681→  const recent = [...charges]
   682→    .sort((a,b) => {
   683→      const ta = new Date(a.createdAt || a.startedAt || 0);
   684→      const tb = new Date(b.createdAt || b.startedAt || 0);
   685→      return tb - ta;
   686→    })
   687→    .slice(0, 50);
   688→
   689→  $('charges-count').textContent = `Showing ${recent.length} of ${charges.length}`;
   690→
   691→  if (!recent.length) {
   692→    $('charges-table-wrap').innerHTML = '<div class="no-data">No charges found for this period.</div>';
   693→    return;
   694→  }
   695→
   696→  const statusClass = s => {
   697→    const st = (s||'').toLowerCase();
   698→    if (st === 'finished' || st === 'completed') return 'badge-green';
   699→    if (st === 'charging' || st === 'ongoing') return 'badge-blue';
   700→    if (st === 'failed' || st === 'error') return 'badge-red';
   701→    return 'badge-gray';
   702→  };
   703→
   704→  $('charges-table-wrap').innerHTML = `
   705→    <div style="overflow-x:auto;">
   706→      <table>
   707→        <thead>
   708→          <tr>
   709→            <th>ID</th>
   710→            <th>Started</th>
   711→            <th>Ended</th>
   712→            <th>Duration</th>
   713→            <th>Energy (kWh)</th>
   714→            <th>Status</th>
   715→            <th>Charge Point</th>
   716→          </tr>
   717→        </thead>
   718→        <tbody>
   719→          ${recent.map(c => {
   720→            const start = c.startedAt || c.startTime || c.createdAt;
   721→            const end   = c.stoppedAt || c.endTime   || c.finishedAt;
   722→            const durMs = (start && end) ? new Date(end) - new Date(start) : null;
   723→            const durMin = durMs ? durMs / 60000 : null;
   724→            const kwh = c.kwh ?? c.energyKwh ?? c.energy;
   725→            const cpName = c.chargePointName || c.chargePoint?.name || c.chargePointId || '—';
   726→            return `<tr>
   727→              <td style="font-family:monospace;font-size:11px;color:var(--text-muted)">${(c.id||'').toString().slice(0,10)}</td>
   728→              <td>${fmtDate(start)}</td>
   729→              <td>${end ? fmtDate(end) : '—'}</td>
   730→              <td>${durMin ? fmtDuration(durMin) : '—'}</td>
   731→              <td>${kwh != null ? fmt(kwh) : '—'}</td>
   732→              <td><span class="badge ${statusClass(c.status)}">${c.status || '—'}</span></td>
   733→              <td>${cpName}</td>
   734→            </tr>`;
   735→          }).join('')}
   736→        </tbody>
   737→      </table>
   738→    </div>`;
   739→}
   740→
   741→// ─── DRAW ALL CHARTS ──────────────────────────────────────────────────────────
   742→function redrawCharts() {
   743→  chartEnergy   = destroyChart(chartEnergy);
   744→  chartSessions = destroyChart(chartSessions);
   745→  chartAvgKwh   = destroyChart(chartAvgKwh);
   746→  chartStatus   = destroyChart(chartStatus);
   747→
   748→  const grouped = groupChargesByPeriod(allCharges);
   749→
   750→  chartEnergy   = buildLineChart('chart-energy',   grouped.labels, grouped.energy,   'Energy (kWh)', GREEN);
   751→  chartSessions = buildLineChart('chart-sessions',  grouped.labels, grouped.sessions, 'Sessions',     BLUE);
   752→  chartAvgKwh   = buildLineChart('chart-avg-kwh',   grouped.labels, grouped.avgKwh,  'Avg kWh',      AMBER);
   753→
   754→  // CP status donut
   755→  const statusMap = {};
   756→  allCPs.forEach(cp => {
   757→    const s = cp.status || 'Unknown';
   758→    statusMap[s] = (statusMap[s] || 0) + 1;
   759→  });
   760→  const statusLabels = Object.keys(statusMap);
   761→  const statusData   = Object.values(statusMap);
   762→  const colorPalette = ['#00C48C','#3b82f6','#f59e0b','#ef4444','#8b5cf6','#6b7280','#ec4899'];
   763→  const statusColors = statusLabels.map((_, i) => colorPalette[i % colorPalette.length]);
   764→
   765→  if (statusLabels.length) {
   766→    chartStatus = buildDonut('chart-status', statusLabels, statusData, statusColors);
   767→  }
   768→}
   769→
   770→// ─── LOAD ALL DATA ────────────────────────────────────────────────────────────
   771→async function loadAll() {
   772→  clearError();
   773→  $('refresh-btn').disabled = true;
   774→  $('status-badge').className = '';
   775→  $('status-badge').textContent = 'Connecting…';
   776→
   777→  try {
   778→    if (!accessToken) await authenticate();
   779→
   780→    const {startDate, endDate} = getDateRange();
   781→    setLoading('Fetching charge sessions…');
   782→
   783→    // Fetch in parallel
   784→    const [charges, cps] = await Promise.all([
   785→      fetchAll('/charges', {startDate, endDate}).catch(e => { console.warn('charges error', e); return []; }),
   786→      fetchAll('/charge-points').catch(e => { console.warn('cp error', e); return []; })
   787→    ]);
   788→
   789→    allCharges = charges;
   790→    allCPs     = cps;
   791→
   792→    setLoading('Rendering dashboard…');
   793→
   794→    renderKPIs(allCharges, allCPs);
   795→    redrawCharts();
   796→    renderChargePoints(allCPs);
   797→    renderChargesTable(allCharges);
   798→
   799→    $('status-badge').className = 'connected';
   800→    $('status-badge').textContent = '● Live';
   801→    $('last-updated').textContent = 'Updated ' + new Date().toLocaleTimeString();
   802→
   803→  } catch (err) {
   804→    console.error(err);
   805→    showError(err.message || String(err));
   806→    $('status-badge').className = 'error';
   807→    $('status-badge').textContent = '✕ Error';
   808→  } finally {
   809→    hideLoading();
   810→    $('refresh-btn').disabled = false;
   811→  }
   812→}
   813→
   814→// ─── INIT ──────────────────────────────────────────────────────────────────────
   815→loadAll();
   816→</script>
   817→</body>
   818→</html>
