// ─── DATE HELPERS ─────────────────────────────────────────────────────────────
// NOTE: Monta API does not support server-side date filtering on /charges.
// We fetch ALL charges once and filter client-side.
function getDateRange() {
  const days = parseInt($('period-select').value) || 30;
  const end = new Date(), start = new Date();
  start.setDate(start.getDate() - days);
  return { startMs: start.getTime(), endMs: end.getTime(), days };
}

function filterChargesByDate(charges) {
  const { startMs, endMs } = getDateRange();
  return charges.filter(c => {
    const ts = new Date(c.startedAt || c.createdAt || 0).getTime();
    return ts >= startMs && ts <= endMs;
  });
}

