// ─── COORDINATE EXTRACTION ────────────────────────────────────────────────────
function getCoords(obj) {
  if (!obj) return null;
  // Flatten nested checks
  const candidates = [
    [obj.lat, obj.lng ?? obj.lon ?? obj.longitude],
    [obj.lat, obj.lng],
    [obj.latitude, obj.longitude],
    [obj.location?.lat, obj.location?.lng ?? obj.location?.lon ?? obj.location?.longitude],
    [obj.location?.latitude, obj.location?.longitude],
    [obj.coordinates?.lat, obj.coordinates?.lng ?? obj.coordinates?.lon],
    [obj.address?.lat, obj.address?.lng ?? obj.address?.lon],
    [obj.site?.lat, obj.site?.lng ?? obj.site?.lon],
    [obj.site?.location?.lat, obj.site?.location?.lng],
    [obj.geoLocation?.lat, obj.geoLocation?.lng],
    [obj.position?.lat, obj.position?.lng],
  ];
  for (const [lat, lng] of candidates) {
    if (lat != null && lng != null && !isNaN(lat) && !isNaN(lng)) {
      const la = parseFloat(lat), lo = parseFloat(lng);
      if (la >= -90 && la <= 90 && lo >= -180 && lo <= 180 && (la !== 0 || lo !== 0)) {
        return [la, lo];
      }
    }
  }
  return null;
}

