function groupChargesByPeriod(charges) {
  const groupBy = $('group-select').value;
  const map = {};
  charges.forEach(c => {
    const raw = c.createdAt || c.startedAt || c.startTime;
    if (!raw) return;
    const d = new Date(raw);
    let key;
    if (groupBy === 'week') {
      const mon = new Date(d);
      mon.setDate(d.getDate() - ((d.getDay() + 6) % 7));
      key = mon.toISOString().split('T')[0];
    } else {
      key = d.toISOString().split('T')[0];
    }
    if (!map[key]) map[key] = {energy: 0, sessions: 0};
    map[key].energy   += c.kwh ?? c.energyKwh ?? c.energy ?? 0;
    map[key].sessions += 1;
  });
  const sorted = Object.keys(map).sort();
  const labels = sorted.map(k => {
    const d = new Date(k + 'T12:00:00');
    return groupBy === 'week'
      ? 'W/c ' + d.toLocaleDateString('en-GB',{day:'2-digit',month:'short'})
      : d.toLocaleDateString('en-GB',{day:'2-digit',month:'short'});
  });
  return {
    labels,
    energy:   sorted.map(k => +map[k].energy.toFixed(2)),
    sessions: sorted.map(k => map[k].sessions),
    avgKwh:   sorted.map(k => map[k].sessions ? +(map[k].energy/map[k].sessions).toFixed(2) : 0)
  };
}

