// ─── RENDER KPIs ─────────────────────────────────────────────────────────────
function renderKPIs(charges, cps) {
  const totalEnergy = charges.reduce((s,c) => s + (c.kwh ?? c.energyKwh ?? c.energy ?? 0), 0);
  const durations   = charges.map(c => {
    const s = c.startedAt||c.startTime||c.createdAt, e = c.stoppedAt||c.endTime||c.finishedAt;
    if (!s||!e) return null;
    const d = (new Date(e)-new Date(s))/60000;
    return (d>0 && d<1440) ? d : null;
  }).filter(Boolean);
  const avgDur = durations.length ? durations.reduce((a,b)=>a+b,0)/durations.length : null;

  $('kpi-energy').textContent       = fmt(totalEnergy) + ' kWh';
  $('kpi-sessions').textContent     = fmt(charges.length);
  $('kpi-duration').textContent     = avgDur ? fmtDuration(avgDur) : '—';
  $('kpi-chargepoints').textContent = fmt(cps.length);

  const {days} = getDateRange();
  $('kpi-energy-sub').textContent   = `kWh over last ${days} days`;
  $('kpi-sessions-sub').textContent = `over last ${days} days`;
  $('kpi-cp-sub').textContent       = `${cps.filter(cp=>statusCategory(cp.status)==='available').length} available now`;
}

