  const g = groupChargesByPeriod(filteredCharges);
  chartEnergy  = buildBarChart('chart-energy',   g.labels, g.energy,   'Energy (kWh)', GREEN);
  chartSessions= buildBarChart('chart-sessions',  g.labels, g.sessions, 'Sessions',     BLUE);
  chartAvgKwh  = buildBarChart('chart-avg-kwh',   g.labels, g.avgKwh,  'Avg kWh',      AMBER);

  // Status donut uses `state` field
  const sm={}, palette=['#00C48C','#3b82f6','#f59e0b','#ef4444','#8b5cf6','#9ca3af','#ec4899'];
  allCPs.forEach(cp => { const s=getState(cp)||'unknown'; sm[s]=(sm[s]||0)+1; });
  const sl=Object.keys(sm), sd=Object.values(sm);
  if (sl.length) chartStatus = buildDonut('chart-status', sl, sd, sl.map((_,i)=>palette[i%palette.length]));
}

