async function loadAll() {
  clearError();
  $('refresh-btn').disabled = true;
  $('status-badge').className = '';
  $('status-badge').textContent = 'Connecting…';
  mapInitialised = false;

  try {
    if (!accessToken) await authenticate();
    const {startDate, endDate} = getDateRange();

    setLoading('Fetching charge sessions…');
    const [charges, cps] = await Promise.all([
      fetchAll('/charges', {startDate, endDate}).catch(e => { console.warn('charges:', e); return []; }),
      fetchAll('/charge-points').catch(e => { console.warn('cps:', e); return []; })
    ]);

    allCharges = charges;
    allCPs     = cps;
    cpStats    = buildCPStats(allCharges);

    setLoading('Rendering dashboard…');

    renderKPIs(allCharges, allCPs);
    redrawCharts();
    renderChargePoints(allCPs);
    renderChargesTable(allCharges);

    // If map tab is active, re-render map
    if ($('view-map').classList.contains('active')) {
      initMap();
    }

    $('status-badge').className = 'connected';
    $('status-badge').textContent = '● Live';
    $('last-updated').textContent = 'Updated ' + new Date().toLocaleTimeString();

  } catch (err) {
    console.error(err);
    showError(err.message || String(err));
    $('status-badge').className = 'error';
    $('status-badge').textContent = '✕ Error';
  } finally {
    hideLoading();
    $('refresh-btn').disabled = false;
  }
}

