(async () => {
  const r = await fetch('https://partner-api.monta.com/api/v1/auth/token', {
    method:'POST', headers:{'Content-Type':'application/json'},
    body: JSON.stringify({clientId:'47095201-e97d-4697-ae5a-d7914655f6cf', clientSecret:'184d8bdb-7820-4d1e-b364-fb61ee3e068b'})
  });
  const {accessToken} = await r.json();
  const r2 = await fetch('https://partner-api.monta.com/api/v1/charges?perPage=3', {
    headers:{Authorization:`Bearer ${accessToken}`}
  });
  const d = await r2.json();
  window._sampleCharge = d.data[0];
  return JSON.stringify(d.data[0], null, 2);
})()

// Show all top-level keys and their values from the sample charge
const c = window._sampleCharge;
const result = {};
Object.keys(c).forEach(k => { result[k] = c[k]; });
JSON.stringify(result, null, 2);

const c = window._sampleCharge;
// Just show keys and primitive values (skip nested objects)
const flat = {};
Object.keys(c).forEach(k => {
  const v = c[k];
  if(typeof v !== 'object' || v === null) flat[k] = v;
  else flat[k] = '[object]';
});
JSON.stringify(flat, null, 2);

const c = window._sampleCharge;
// Show price-related and remaining primitive fields
const keys = Object.keys(c).filter(k => typeof c[k] !== 'object' || c[k] === null);
const result = {};
keys.forEach(k => result[k] = c[k]);
// Also check startedAt vs stoppedAt difference in seconds
if(c.startedAt && c.stoppedAt) {
  result['_calcDurSeconds'] = (new Date(c.stoppedAt) - new Date(c.startedAt)) / 1000;
}
JSON.stringify(result, null, 2);

