// ── Duration helper (API has no duration field — calc from timestamps) ────────
function getDurS(c){
  // Prefer stoppedAt - startedAt, fall back to completedAt, then releasedAt
  const start = c.startedAt || c.cablePluggedInAt || c.createdAt;
  const end   = c.stoppedAt || c.completedAt || c.releasedAt || c.updatedAt;
  if(start && end){
    const diff = (new Date(end) - new Date(start)) / 1000;
    if(diff > 0 && diff < 86400 * 7) return diff; // sanity cap at 7 days
  }
  return 0;
}

// ── Cost model ────────────────────────────────────────────────────────────────

